#include <iostream>
using namespace std;

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    ArrayInt a1(arr, 5);

    cout << "Original Array: ";
    a1.display();

    ArrayInt a2 = a1; // Tests copy constructor

    cout << "Testing += int:" << endl;
    a1 += 6;
    a1.display();

    cout << "Testing += ArrayInt:" << endl;
    int arr2[] = {7, 8};
    ArrayInt a3(arr2, 2);
    a1 += a3;
    a1.display();

    cout << "Testing -= int:" << endl;
    a1 -= 3;
    a1.display();

    cout << "Testing -= ArrayInt:" << endl;
    int arr3[] = {1, 5};
    ArrayInt a4(arr3, 2);
    a1 -= a4;
    a1.display();

    if (a1 != a2) {
        cout << "Arrays are correctly different." << endl;
    }

    return 0;
}
